SELECT user_id, SUM(cost) AS total_spent
FROM license_purchases
GROUP BY user_id;

SELECT license_name, 
       LEAD(license_name) OVER(ORDER BY license_id) AS next_license_name
FROM licenses;

SELECT users.user_name, email_services.email_service_name
FROM users
JOIN email_services ON users.email_service_id = email_services.email_service_id;

SELECT l.license_name
FROM licenses l
JOIN user_license_dependencies uld ON l.license_id = uld.license_id;

SELECT user_id 
FROM license_purchases 
WHERE license_id = 1 AND sales_channel_id = 1;

SELECT COUNT(DISTINCT user_id)
FROM license_purchases
WHERE sales_channel_id = 1;

SELECT license_name, license_duration 
FROM licenses 
WHERE license_duration > (SELECT AVG(license_duration) FROM licenses);
